uotes import Quotes\\nimport pandas as pd\\nimport numpy as np\\nfrom concurrent.futures import ThreadPoolExecutor, as_completed\\nfrom datetime import datetime\\nimport os\\n\\n# 初始化客户端\\nclient = Quotes.factory(market='std')\\n\\n# 获取创业板股票列表（300开头）\\nprint(\\\"获取创业板股票列表...\\\")\\nall_stocks = client.stock_all()\\ngem_stocks = all_stocks[all_stocks['code'].str.startswith('300')].copy()\\nprint(f\\\"创业板股票总数: {len(gem_stocks)}\\\")\\n\\n# 定义获取单只股票波动率的函数\\ndef get_volatility(code):\\n    try:\\n        # 获取K线数据，offset=15确保有足够的前10交易日数据\\n        bars = client.bars(symbol=code, frequency=9, offset=15)\\n        \\n        if bars is None or len(bars) < 10:\\n            return None\\n        \\n        # 按日期排序，取最近10条\\n        bars = bars.sort_index()\\n        recent_10 = bars.tail(10)\\n        \\n        # 计算波动率 = std(close) / mean(close) * 100%\\n        close_prices = recent_10['close']\\n        volatility = (close_prices.std() / close_prices.mean()) * 100\\n        \\n        return {\\n            'code': code,\\n            'volatility': volatility\\n        }\\n    except Exception as e:\\n        return None\\n\\n# 并发获取所有创业板股票的波动率\\nprint(\\\"开始并发获取波动率数据...\\\")\\nresults = []\\nsuccess_count = 0\\nfail_count = 0\\n\\nwith ThreadPoolExecutor(max_workers=12) as executor:\\n    futures = {executor.submit(get_volatility, row['code']): row['code'] \\n               for _, row in gem_stocks.iterrows()}\\n    \\n    for i, future in enumerate(as_completed(futures), 1):\\n        result = future.result()\\n        if result is not None:\\n            results.append(result)\\n            success_count += 1\\n        else:\\n            fail_count += 1\\n        \\n        if i % 100 == 0:\\n            print(f\\\"进度: {i}/{len(gem_stocks)}, 成功: {success_count}, 失败: {fail_count}\\\")\\n\\nprint(f\\\"\\\\n数据获取完成: 成功 {success_count}, 失败 {fail_count}\\\")\\n\\n# 按波动率降序排序，取前5名\\nif len(results) > 0:\\n    df = pd.DataFrame(results)\\n    df = df.sort_values('volatility', a